 * ================================================= */
void example_epoll_one(void) {
    int fd[2]; pipe(fd);
    if (fork() == 0) {
        close(fd[0]);
        write(fd[1], "evt", 3);
        close(fd[1]); _exit(0);
    }
    close(fd[1]);
    int epfd = epoll_create1(0);
    struct epoll_event ev = { .events = EPOLLIN, .data.fd = fd[0] };
    epoll_ctl(epfd, EPOLL_CTL_ADD, fd[0], &ev);
    struct epoll_event evts[1];
    epoll_wait(epfd, evts, 1, -1);
    char buf[16];
    ssize_t n = read(evts[0].data.fd, buf, sizeof(buf)-1);
    buf[n] = '\0';
    printf("Got: %s\n", buf);
    close(fd[0]); close(epfd); wait(NULL);
}
